import React from "react";
import { useState } from "react";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Select } from "@/components/ui/select";
import SelectInput from "react-select";
import MultiSelectDropdown from "../../../components/MultiSelectDropdown";

const CreateRecipe = () => {
  const [selectedTags, setSelectedTags] = useState<string[]>([]);

  // Handle the selected tags
  const handleTagChange = (tags: string[]) => {
    setSelectedTags(tags);
  };

  return (
    <div className="container mx-auto p-4">
      <h1 className="text-2xl font-bold mb-4">Create Recipe</h1>
      <form>
        <div className="mb-4">
          <Label
            htmlFor="recipe-name"
            className="block text-sm font-medium text-gray-700"
          >
            Name
          </Label>
          <Input
            type="text"
            id="recipe-name"
            placeholder="Name"
            className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-green-500 focus:ring-green-500 sm:text-sm"
          />
          <Label htmlFor="recipe-tag">Tag</Label>
          {/* <Input type="" id="tags" placeholder="Tags" /> */}
          <MultiSelectDropdown
            initialTags={selectedTags} // Pass selected tags when editing
            onTagChange={handleTagChange} // Callback to update selected tags
          />
        </div>
        <Button
          type="submit"
          className="bg-green-600 text-white px-4 py-2 rounded hover:bg-green-700"
        >
          Submit
        </Button>
      </form>
    </div>
  );
};

export default CreateRecipe;
